import json
baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p['resolvedVersion']
        result[name] = pkgs
    return result

b = extract(baseline)
a = extract(after)
diffs = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = b.get(proj, {})
    ap = a.get(proj, {})
    for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pkg, 'MISSING')
        av = ap.get(pkg, 'MISSING')
        if bv != av:
            print(f'DIFF: {proj} {pkg}: {bv} -> {av}')
            diffs = True
if not diffs:
    print('All packages match baseline - conversion is version-neutral')
